/* Suggested markup: <div class="uiwiki-confidence-route-input" tabindex="0"><span>Confidence Route Input</span></div> */
.uiwiki-confidence-route-input {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-confidence-route-input > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #f5e642;
  animation: confidence_route_input 1.8s ease-in-out infinite alternate;
}
.uiwiki-confidence-route-input:hover,
.uiwiki-confidence-route-input:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes confidence_route_input {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-confidence-route-input, .uiwiki-confidence-route-input > span { animation: none; transition: none; }
}
